#include <bits/stdc++.h>
using namespace std;

int n, q, f[105][105];
bool vis[105];
vector<pair<int, int> > m[105];

int DFS(int k) {
    vis[k] = true;
    if (m[k].size() == 1) 
        return 1;
    int branch = 0;
    int l = 0, r = 0, l_apple = 0, r_apple = 0;
    for (auto i : m[k]) {
        int son = i.first;
        int apple = i.second;
        if (vis[son]) 
            continue;
        if (!l) {
            l = son;
            l_apple = apple;
        }
        else {
            r = son;
            r_apple = apple;
        }
        branch += DFS(son);
    }

    for(int i = 1; i <= branch; i++){ //遍历该节点所有子树枝数量
        for(int j = 0; j <= i; j++){
            int lb = j - 1;
            int rb = i - j - 1;
            if(j == 0){ //左子节点不分配树枝
                f[k][i] = max(
                    f[k][i], 
                    f[r][rb] + r_apple
                ); //注意i-1，剪掉连接子节点1根树枝
            }
            else if(j == i){ //右子节点不分配树枝
                f[k][i] = max(
                    f[k][i], 
                    f[l][lb] + l_apple
                );
            }
            else {
                f[k][i] = max(
                    f[k][i], 
                    f[l][lb] + f[r][rb] + l_apple + r_apple
                );
            }
        }
    }
    return branch + 1;
}

int main() {
    cin >> n >> q;
    for (int i = 0; i < n - 1; i++) {
        int a, b, c;
        cin >> a >> b >> c;
        m[a].push_back(make_pair(b, c));
        m[b].push_back(make_pair(a, c));
    }
    DFS(1);
    cout << f[1][q];
    return 0;
}
